@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <input type="text" placeholder="Title" @bind="title" />
        <input type="text" placeholder="Assignee" @bind="assignee" />
        <select @bind="priority">
            <option value="High">High</option>
            <option value="Medium">Medium</option>
            <option value="Low">Low</option>
        </select>
        <input type="date" @bind="dueDate" />
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@isSaving">Save</button>
            <button class="btn-cancel" @onclick="Cancel">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter, EditorRequired]
    public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate)> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        IsVisible = false;
        ResetForm();
    }

    private async Task Save()
    {
        if (string.IsNullOrWhiteSpace(title))
            return;

        isSaving = true;
        try
        {
            await OnTaskCreated.InvokeAsync((title, assignee, priority, dueDate));
            IsVisible = false;
            ResetForm();
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

