arguments.file_text:
@page "/board"
@rendermode InteractiveServer
@using sv_61a0e5156f424a1599c34c8817bb4986.Components.Board
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

@if (isLoading)
{
    <p class="board-message">Loading tasks…</p>
}
else if (errorMessage is not null)
{
    <div class="board-error">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStatsBar Tasks="allTasks" />

    <BoardSearchBar @bind-SearchText="searchText" />

    <div class="board-columns">
        <BoardColumn ColumnName="To Do"
                     Tasks="GetTasksForStatus("To Do")"
                     ShowMoveLeft="false"
                     ShowMoveRight="true"
                     OnMoveRight="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="args => CreateTask(args, "To Do")" />

        <BoardColumn ColumnName="In Progress"
                     Tasks="GetTasksForStatus("In Progress")"
                     ShowMoveLeft="true"
                     ShowMoveRight="true"
                     OnMoveLeft="task => MoveTask(task, "To Do")"
                     OnMoveRight="task => MoveTask(task, "Done")"
                     OnTaskCreated="args => CreateTask(args, "In Progress")" />

        <BoardColumn ColumnName="Done"
                     Tasks="GetTasksForStatus("Done")"
                     ShowMoveLeft="true"
                     ShowMoveRight="false"
                     OnMoveLeft="task => MoveTask(task, "In Progress")"
                     OnTaskCreated="args => CreateTask(args, "Done")" />
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetTasksForStatus(string status) =>
        allTasks
            .Where(t => t.Status == status &&
                        (string.IsNullOrWhiteSpace(searchText) ||
                         t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase)))
            .ToList();

    private async Task MoveTask(TaskItem task, string newStatus)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(task.Id, newStatus);
            allTasks = allTasks
                .Select(t => t.Id == task.Id ? t with { Status = newStatus } : t)
                .ToList();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private async Task CreateTask(
        (string Title, string Assignee, string Priority, DateTime DueDate) args,
        string status)
    {
        try
        {
            var created = await TaskService.CreateTaskAsync(args.Title, args.Assignee, args.Priority, args.DueDate);
            allTasks.Add(created with { Status = status });
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to create task: {ex.Message}";
